import { memo } from "react";
import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";
import { ArrowRight, Calendar, Users, Pin } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { useActivities } from "@/hooks/useActivities";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";

const LoadingSkeleton = memo(() => (
  <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
    {Array.from({ length: 4 }).map((_, i) => (
      <Card key={i} className="overflow-hidden">
        <Skeleton className="aspect-[16/9] w-full" />
        <div className="p-4 space-y-2">
          <Skeleton className="h-5 w-3/4" />
          <Skeleton className="h-4 w-1/2" />
        </div>
      </Card>
    ))}
  </div>
));
LoadingSkeleton.displayName = "ActivitiesSkeleton";

const HomeRecentActivitiesSection = memo(() => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { data: activities, isLoading } = useActivities();
  const { getLocalizedField } = useLocalizedContent();

  // Filter visible + published, take first 3
  const recentActivities = (activities || [])
    .filter((a) => a.visible && a.status === "published")
    .slice(0, 4);

  if (!isLoading && recentActivities.length === 0) return null;

  const isEnded = (endDate: string | null) => {
    if (!endDate) return false;
    return new Date(endDate) < new Date();
  };

  return (
    <section className="py-8 sm:py-12 px-4 bg-secondary/20">
      <div className="container mx-auto max-w-7xl">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-xl sm:text-2xl font-bold text-foreground">
            {t("home.recentActivities.title")}
          </h2>
        </div>

        {isLoading ? (
          <LoadingSkeleton />
        ) : (
          <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
            {recentActivities.map((activity) => {
              const title = getLocalizedField(activity, "title") || activity.title_zh;
              const ended = isEnded(activity.end_date);

              return (
                <Card
                  key={activity.id}
                  className="group cursor-pointer overflow-hidden hover:shadow-lg transition-all duration-300 border-border/50 bg-card rounded-xl"
                  onClick={() => navigate(`/activities/${activity.id}`)}
                >
                  <div className="relative aspect-[16/9] overflow-hidden bg-muted">
                    {activity.image_url ? (
                      <img
                        src={activity.image_url}
                        alt={title}
                        className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
                        loading="lazy"
                      />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center bg-gradient-to-br from-primary/20 to-primary/5">
                        <Calendar className="w-12 h-12 text-primary/40" />
                      </div>
                    )}
                    <div className="absolute top-2 left-2 flex gap-1.5">
                      {activity.pinned && (
                        <Badge variant="secondary" className="text-xs bg-background/80 backdrop-blur-sm">
                          <Pin className="w-3 h-3 mr-1" />
                          {t("activities.pinned")}
                        </Badge>
                      )}
                      {ended && (
                        <Badge variant="destructive" className="text-xs">
                          {t("activities.ended")}
                        </Badge>
                      )}
                    </div>
                  </div>
                  <div className="p-4 space-y-2">
                    <h3 className="font-semibold text-sm leading-tight line-clamp-2 text-foreground group-hover:text-primary transition-colors">
                      {title}
                    </h3>
                    <div className="flex items-center gap-3 text-xs text-muted-foreground">
                      <span className="flex items-center gap-1">
                        <Calendar className="w-3 h-3" />
                        {new Date(activity.start_date).toLocaleDateString()}
                      </span>
                      {!ended && activity.subscriber_count != null && activity.subscriber_count > 0 && (
                        <span className="flex items-center gap-1">
                          <Users className="w-3 h-3" />
                          {activity.subscriber_count}
                        </span>
                      )}
                    </div>
                  </div>
                </Card>
              );
            })}
          </div>
        )}

        {!isLoading && recentActivities.length > 0 && (
          <div className="flex justify-center mt-6">
            <Button variant="outline" size="lg" className="gap-2" onClick={() => navigate("/activities")}>
              {t("home.recentActivities.enterActivities")}
              <ArrowRight className="w-4 h-4" />
            </Button>
          </div>
        )}
      </div>
    </section>
  );
});
HomeRecentActivitiesSection.displayName = "HomeRecentActivitiesSection";

export default HomeRecentActivitiesSection;
